MonsterManager = {}
MonsterManager.Changing = false

MonsterManager.MonsterRegionCount = {} --怪物在某个区域的数量
MonsterManager.MonsterRegionCount[Define.RefreshType.TypeDefault] = {}
MonsterManager.MonsterRegionCount[Define.RefreshType.TypeSpecial] = {}

--待刷新的怪物列表
MonsterManager.refreshList = {}
MonsterManager.refreshList[Define.RefreshType.TypeDefault] = {}
MonsterManager.refreshList[Define.RefreshType.TypeSpecial] = {}

--刷怪间隔数据
MonsterManager.refreshTimeData = {}
MonsterManager.refreshTimeData[Define.RefreshType.TypeDefault] = {}
MonsterManager.refreshTimeData[Define.RefreshType.TypeSpecial] = {}

MonsterManager.Monsters = {} --怪物列表

function MonsterManager:addMonster(data, type)
    local config = MonsterConfig:getMonsterConfig(data.monsterId) --配置数据
    if config == nil then
        return 0
    end

    local birthPos = VectorUtil.newVector3(data.birthPos.x + 0.5,
            data.birthPos.y, data.birthPos.z + 0.5)
    local monster = GameMonster.new(data.monsterId, data.regionId, data.strRegionArea, birthPos, type, false)
    MonsterManager.Monsters[monster.entityId] = monster
    --HostApi.log("MonsterManager.Monsters[entityId] = monster " .. entityId)
    return monster.entityId
end

function MonsterManager:addMonster2(monster)
    MonsterManager.Monsters[monster.entityId] = monster
end

function MonsterManager:getMonster(entityId)
    return MonsterManager.Monsters[entityId]
end

function MonsterManager:getMonsters()
    return MonsterManager.Monsters
end

function MonsterManager:removeMonster(entityId)
    MonsterManager.Monsters[entityId] = nil
    --HostApi.log("self.Monsters count " .. #self.Monsters)
end

function MonsterManager:onTick(ticks)
    --local time1 = os.clock()

    if EngineWorld:isNight() and not MonsterManager.Changing then
        MonsterConfig:prepareMonsterNightAttr()
        MonsterManager.Changing = true
    elseif not EngineWorld:isNight() and MonsterManager.Changing then
        MonsterConfig:prepareMonster()
        MonsterManager.Changing = false
    end
    MonsterManager:checkRefreshMonster(ticks)

    --local time2 = os.clock()
    MonsterManager:doRefreshMonster(ticks, Define.RefreshType.TypeDefault)
    MonsterManager:doRefreshMonster(ticks, Define.RefreshType.TypeSpecial)
    --HostApi.log(string.format("MonsterManager:doRefreshMonster %f", (os.clock() - time2) * 1000))

    --local time2 = os.clock()
    local monsterCount = 0
    for _, monster in pairs(self.Monsters) do
        monster:onTick(ticks)
        monsterCount = monsterCount + 1
    end
    --HostApi.log(string.format("monster:onTick %f", (os.clock() - time2) * 1000))

    --HostApi.log(string.format("MonsterManager:onTick %f", (os.clock() - time1) * 1000))

    --HostApi.log("MonsterManager.Monsters " .. monsterCount)
end


function MonsterManager:checkRefreshMonster(ticks)
    for _, vRegionData in pairs(MonsterRegionConfig.MonsterRegionData) do
        MonsterManager:refreshDefaultMonster(vRegionData, ticks)
        MonsterManager:refreshSpecialMonster(vRegionData, ticks)
    end
end

function MonsterManager:doRefreshMonster(ticks, type)
    if self.refreshList[type] == nil then
        return
    end
    for strRegionArea, _ in pairs(self.refreshList[type]) do
        if self.refreshList[type][strRegionArea] ~= nil and #self.refreshList[type][strRegionArea] ~= 0 then
            if self.refreshTimeData[type][strRegionArea].ticks % self.refreshTimeData[type][strRegionArea].refreshIntervalSec == 0
             then
                local count = math.min(#self.refreshList[type][strRegionArea], self.refreshTimeData[type][strRegionArea].refreshIntervalNum)
                for i = 1, count do
                    MonsterManager:realRefreshMonster(self.refreshList[type][strRegionArea][1], type)
                    table.remove(self.refreshList[type][strRegionArea], 1)
                end
                --HostApi.log("table.remove(self.refreshList[type][strRegionArea]) " .. #self.refreshList[type][strRegionArea])
            end
            self.refreshTimeData[type][strRegionArea].ticks =
                self.refreshTimeData[type][strRegionArea].ticks + ticks
        else
            self.refreshTimeData[type][strRegionArea].ticks = 0
        end
        self.refreshTimeData[type][strRegionArea].checkTime =
            self.refreshTimeData[type][strRegionArea].checkTime + ticks
    end
end

function MonsterManager:realRefreshMonster(data, type)
    local entityId = MonsterManager:addMonster(data, type)
    if entityId ~= 0 then
        MonsterManager:incMonsterRegionCount(type, data.strRegionArea, 1)
    end
end

function MonsterManager:incMonsterRegionCount(type, strRegionArea, count)
    if self.MonsterRegionCount[type][strRegionArea] == nil then
        self.MonsterRegionCount[type][strRegionArea] = 0
    end
    self.MonsterRegionCount[type][strRegionArea] = self.MonsterRegionCount[type][strRegionArea] + count

    if self.MonsterRegionCount[type][strRegionArea] <= 0 and type == Define.RefreshType.TypeSpecial then
        MonsterRegionConfig.MonsterRegionData[strRegionArea].hasCorpseTide = false
        --HostApi.log("MonsterRegionConfig.MonsterRegionData[strRegionArea].hasCorpseTide = false " .. strRegionArea)
    end

    --HostApi.log(os.clock() .. string.format(" MonsterManager:incMonsterRegionCount %d %s %d %d",
    --        type, strRegionArea, count, self.MonsterRegionCount[type][strRegionArea]))
end

function MonsterManager:checkPlayerInRegion(minX, maxX, minY, maxY, minZ, maxZ)
    local radius = 20
    for _, vPlayer in pairs(PlayerManager:getPlayers()) do
        if vPlayer:playerInRegion(minX - radius, maxX + radius,
                minY - radius, maxY + radius, minZ - radius, maxZ + radius) then
            return true
        end
    end
    return false
end

--清理区域的所有怪物
function MonsterManager:clearMonsterInRegion(regionId)
    for _, vMonster in pairs(MonsterManager:getMonsters()) do
        if vMonster and (vMonster.regionId == regionId) then
            vMonster:onRemove()
        end
    end
end

function MonsterManager:refreshDefaultMonster(data, ticks)
    if data == nil or data.minMonsterCount == nil or data.maxMonsterCount == nil or
            data.refreshPos[Define.RefreshType.TypeDefault] == nil or
            #data.refreshPos[Define.RefreshType.TypeDefault] == 0 then
        return
    end

    --区域没有玩家不刷怪
    if MonsterManager:checkPlayerInRegion(data.tbRegionArea[1].x, data.tbRegionArea[2].x,
            data.tbRegionArea[1].y, data.tbRegionArea[2].y, data.tbRegionArea[1].z, data.tbRegionArea[2].z) == false then
        MonsterManager:clearMonsterInRegion(data.regionId)
        return
    end
    --首次刷怪
    if self.MonsterRegionCount[Define.RefreshType.TypeDefault][data.strRegionArea] == nil then
        --HostApi.log("first refresh monster " .. data.strRegionArea)
        --随机刷怪点位置
        local ret = MonsterManager:getMonsterCountPerPos(data.refreshPos[Define.RefreshType.TypeDefault], data.maxMonsterCount)
        for i = 1, #data.refreshPos[Define.RefreshType.TypeDefault] do
            MonsterManager:refreshMonster(data, data.refreshPos[Define.RefreshType.TypeDefault][i], ret[i], Define.RefreshType.TypeDefault)
        end
    else
        local monsterRegionCount = MonsterManager:getMonsterRegionCount(data.strRegionArea, Define.RefreshType.TypeDefault)

        --当该区域的怪的数量少于最小数量的时候，立刻补充怪的数量达到最小数量，并且重置“检测间隔“的时间
        if monsterRegionCount < data.minMonsterCount then
            --HostApi.log("refresh min size monster")
            local count = data.minMonsterCount - monsterRegionCount
            local ret = MonsterManager:getMonsterCountPerPos(data.refreshPos[Define.RefreshType.TypeDefault], count)
            for i = 1, #data.refreshPos[Define.RefreshType.TypeDefault] do
                MonsterManager:refreshMonster(data, data.refreshPos[Define.RefreshType.TypeDefault][i], ret[i], Define.RefreshType.TypeDefault)
            end
            --重置“检测间隔“的时间
            self.refreshTimeData[Define.RefreshType.TypeDefault][data.strRegionArea].checkTime = 0
        elseif monsterRegionCount < data.maxMonsterCount then
            --补充怪物到最大数量
            if
                self.refreshTimeData[Define.RefreshType.TypeDefault][data.strRegionArea].checkTime %
                    self.refreshTimeData[Define.RefreshType.TypeDefault][data.strRegionArea].checkInterval == 0 then
                --HostApi.log("refresh max size monster")
                local count = data.maxMonsterCount - monsterRegionCount
                local ret =
                    MonsterManager:getMonsterCountPerPos(
                    data.refreshPos[Define.RefreshType.TypeDefault],
                    count
                )
                for i = 1, #data.refreshPos[Define.RefreshType.TypeDefault] do
                    MonsterManager:refreshMonster(data, data.refreshPos[Define.RefreshType.TypeDefault][i], ret[i], Define.RefreshType.TypeDefault)
                end
                self.refreshTimeData[Define.RefreshType.TypeDefault][data.strRegionArea].checkTime = 0
            end
        end
    end
end

--获取每个位置应该刷的怪物数量
function MonsterManager:getMonsterCountPerPos(refreshPos, needMonsterCount)
    --HostApi.log("----------------------------------------------------")
    local result = MathUtil:randomIntNoRepeat(1, #refreshPos, needMonsterCount % #refreshPos)
    --HostApi.log("MathUtil:randomIntNoRepeat " .. table.concat(result, " "))
    local waveCount = math.floor(needMonsterCount / #refreshPos)
    --HostApi.log("MonsterManager:getMonsterCountPerPos " .. waveCount)

    local ret = {}
    for i = 1, #refreshPos do
        local totalCount = waveCount
        if BaseUtil:isTableHave(result, i) then
            totalCount = totalCount + 1
        end
        table.insert(ret, totalCount)
    end

    --HostApi.log(table.concat(ret, " "))

    return ret
end

--获取一个区域怪物的数量（包含还未生成的怪物）
function MonsterManager:getMonsterRegionCount(strRegionArea, type)
    return self.MonsterRegionCount[type][strRegionArea] + #self.refreshList[type][strRegionArea]
end

function MonsterManager:refreshSpecialMonster(data, ticks)
    MonsterManager:refreshSpecialMonsterNight(data)
end

--白天刷尸潮
function MonsterManager:refreshSpecialMonsterDay(pos)
    if EngineWorld:isNight() then
        return
    end

    local resultPos = nil
    local data = nil
    for _, vRegionData in pairs(MonsterRegionConfig.MonsterRegionData) do
        if vRegionData.hasCorpseTide == false then
            for _, vRefreshPos in pairs(vRegionData.refreshPos[Define.RefreshType.TypeSpecial]) do
                local distance = MathUtil:distanceSquare3d(pos, vRefreshPos)
                if distance <= math.pow(MonsterRuleConfig.specialMonsterRefreshRadius, 2) then
                    if resultPos == nil then
                        resultPos = vRefreshPos
                        data = vRegionData
                    elseif distance > MathUtil:distanceSquare3d(pos, resultPos) then
                        resultPos = vRefreshPos
                        data = vRegionData
                    end
                end
            end
        end
    end

    if resultPos == nil then
        --HostApi.log("MonsterManager:refreshSpecialMonsterDay resultPos == nil")
        return
    end

    local count = math.random(data.specialMonsterCount[1], data.specialMonsterCount[2])
    MonsterManager:refreshMonster(data, resultPos, count, Define.RefreshType.TypeSpecial)
    local monsters = MonsterGroupConfig:getAllMonsterFromGroup(data.bossMonsterGroup)
    if monsters ~= nil then
        MonsterManager:refreshBossMonster(data, resultPos, #monsters,
                Define.RefreshType.TypeSpecial, monsters)
    end
    MonsterRegionConfig.MonsterRegionData[data.strRegionArea].hasCorpseTide = true

    --HostApi.log(string.format("MonsterManager:refreshSpecialMonsterDay %s", data.strRegionArea))
end

function MonsterManager:refreshSpecialMonsterNight(data)
    if not EngineWorld:isNight() then
        return
    end

    local players = PlayerManager:getPlayers()
    for _, player in pairs(players) do
        local inRegion = player:playerInRegion(data.tbRegionArea[1].x, data.tbRegionArea[2].x,
                data.tbRegionArea[1].y, data.tbRegionArea[2].y,
                data.tbRegionArea[1].z, data.tbRegionArea[2].z)
        if inRegion == true and data.hasCorpseTide == false then
            local count = math.random(data.specialMonsterCount[1], data.specialMonsterCount[2])
            local ret = MonsterManager:getMonsterCountPerPos(data.refreshPos[Define.RefreshType.TypeSpecial], count)
            for i = 1, #data.refreshPos[Define.RefreshType.TypeSpecial] do
                MonsterManager:refreshMonster(data, data.refreshPos[Define.RefreshType.TypeSpecial][i], ret[i], Define.RefreshType.TypeSpecial)
            end
            --刷boss怪物
            local monsters = MonsterGroupConfig:getAllMonsterFromGroup(data.bossMonsterGroup)
            if monsters ~= nil then
                local ret = MonsterManager:getMonsterCountPerPos(data.refreshPos[Define.RefreshType.TypeSpecial], #monsters)
                local offset = 0
                for i = 1, #data.refreshPos[Define.RefreshType.TypeSpecial] do
                    local monsterList = {}
                    for i = 1, ret[i] do
                        table.insert(monsterList, monsters[offset + i])
                    end
                    MonsterManager:refreshBossMonster(data, data.refreshPos[Define.RefreshType.TypeSpecial][i], ret[i],
                            Define.RefreshType.TypeSpecial, monsterList)
                    offset = offset + ret[i]
                end
            end
            data.hasCorpseTide = true
            --HostApi.log(string.format("MonsterManager:refreshSpecialMonsterNight strRegionArea:%s count:%d",
            --        data.strRegionArea, count))
        end
    end

    --HostApi.log(string.format("MonsterManager:refreshSpecialMonsterNight %s", data.strRegionArea))
end

function MonsterManager:refreshMonster(vRegionData, pos, count, type)
    if vRegionData == nil or count == 0 then
        --HostApi.log("MonsterManager:refreshMonster vRegionData == nil or count == 0")
        return
    end

    --HostApi.log(string.format("MonsterManager:refreshMonster %s %d %d", vRegionData.strRegionArea, count, type))

    if type ~= Define.RefreshType.TypeBoss then
        --重新计算刷怪位置
        --local result = MonsterManager:adjustRefreshMonsterPos(pos, count)

        for i = 1, count do
            local data = {}
            data.regionId = vRegionData.regionId
            data.strRegionArea = vRegionData.strRegionArea
            data.birthPos = {}
            data.birthPos.x = pos.x
            data.birthPos.y = pos.y
            data.birthPos.z = pos.z

            if type == Define.RefreshType.TypeDefault then
                data.monsterId = MonsterGroupConfig:getMonsterFromGroup(vRegionData.defaultMonsterGroup)
            else
                data.monsterId = MonsterGroupConfig:getMonsterFromGroup(vRegionData.specialMonsterGroup)
            end

            if self.refreshList[type][data.strRegionArea] == nil then
                self.refreshList[type][data.strRegionArea] = {}
            end
            --HostApi.log("table.insert(self.refreshList[type][data.strRegionArea], data) " ..
            --        data.monsterId .. " " .. data.birthPos.x .. " " .. data.birthPos.y .. " " .. data.birthPos.z)
            table.insert(self.refreshList[type][data.strRegionArea], data)

            if self.refreshTimeData[type][data.strRegionArea] == nil then
                self.refreshTimeData[type][data.strRegionArea] = {}
                self.refreshTimeData[type][data.strRegionArea].refreshIntervalSec,
                self.refreshTimeData[type][data.strRegionArea].refreshIntervalNum = MonsterManager:getRefreshInterval(vRegionData, type)
                self.refreshTimeData[type][data.strRegionArea].checkInterval = vRegionData.checkInterval
                self.refreshTimeData[type][data.strRegionArea].checkTime = 0 --检测间隔时间
                self.refreshTimeData[type][data.strRegionArea].ticks = 0 --Region ticks
            end
        end
    end
end

function MonsterManager:refreshBossMonster(vRegionData, pos, count, type, monsters)
    -- boss怪物刷新

    --生成该怪物组里面的全部怪
    --local monsterPos = MonsterManager:adjustRefreshMonsterPos(pos, #monsters)
    for i = 1, #monsters do
        local data = {}
        data.regionId = vRegionData.regionId
        data.strRegionArea = vRegionData.strRegionArea
        data.birthPos = {}
        data.birthPos.x = pos.x
        data.birthPos.y = pos.y
        data.birthPos.z = pos.z
        data.monsterId = monsters[i].MonsterId

        if self.refreshList[type][data.strRegionArea] == nil then
            self.refreshList[type][data.strRegionArea] = {}
        end
        table.insert(self.refreshList[type][data.strRegionArea], data)

        if self.refreshTimeData[type][data.strRegionArea] == nil then
            self.refreshTimeData[type][data.strRegionArea] = {}
            self.refreshTimeData[type][data.strRegionArea].refreshIntervalSec,
            self.refreshTimeData[type][data.strRegionArea].refreshIntervalNum = MonsterManager:getRefreshInterval(vRegionData, type)
            self.refreshTimeData[type][data.strRegionArea].checkInterval = vRegionData.checkInterval
            self.refreshTimeData[type][data.strRegionArea].checkTime = 0 --检测间隔时间
            self.refreshTimeData[type][data.strRegionArea].ticks = 0 --Region ticks
        end
    end

    --HostApi.log("refresh boss monster")
end

function MonsterManager:getRefreshInterval(data, type)
    --HostApi.log("MonsterManager:getRefreshInterval")

    if type == Define.RefreshType.TypeDefault then
        return data.defaultRefreshIntervalSec,data.defaultRefreshIntervalNum
    else
        return data.specialRefreshIntervalSec,data.specialRefreshIntervalNum
    end
end

function MonsterManager:adjustRefreshMonsterPos(pos, count)
    --HostApi.log("MonsterManager:adjustRefreshMonsterPos")

    --在原点周围偏移X(直径)距离的正方体范围内随机选择地表的点上生成（X=3+（要生成的怪物数量/8）），选取的点不重复
    local radius = math.floor((3 + math.floor(count / 8)) / 2)

    local minX = pos.x - radius
    local maxX = pos.x + radius
    local minZ = pos.z - radius
    local maxZ = pos.z + radius
    local result = MathUtil:randomInRect(minX, maxX, minZ, maxZ, count)

    return result
end

return MonsterManager
